                    res += countNumbersWithPopcountAndDepth(pop, k - 1) * combinations(remainingLength - 1, pop - 1)
                }
                ones++
            }
        }

        if (k == 1 && (n and (n - 1)) == 0L && n != 1L) {
            res++
        }

        return res
    }

    return if (k >= 60) 0 else countNumbersUpToNWithDepthK(n, k.toInt())
}
